 飞机降落 # dfs 暴力搜索
#include&lt;iostream&gt; #include&lt;cstring&gt; using namespace std; const int N = 15; struct Plane{ int t; int d; int l; }p[N]; int n; bool st[N]; bool dfs(int u, int last){ if(u == n) return true; for(int i = 0 ; i &lt; n ; i ++){ int t = p[i].t,d = p[i].d, l = p[i].l; //当前点 没选过 并且 飞机能够降落的最后时间 比上一架飞机的降落时间 靠后 //满足这种情况 可以降落 if(!st[i] &amp;&amp; t + d &gt;= last){ st[i] = true; if(dfs(u + 1, max(last,t) + l)) return true; st[i] = false; } } return false; } int main(){ int T; cin &gt;&gt; T; while(T --){ cin &gt;&gt; n; for(int i = 0 ; i &lt; n ; i ++){ cin &gt;&gt; p[i].t &gt;&gt; p[i].d &gt;&gt; p[i].l; } //每次结束后 都要 重新初始化st数组，避免上组数据 影响下一组 memset(st,0,sizeof st); if(dfs(0,0)) cout &lt;&lt; &#34;YES&#34; &lt;&lt; endl; else cout &lt;&lt; &#34;NO&#34; &lt;&lt; endl; } return 0; } $O(N!)$
状态压缩DP
$O(2^n /times nT)$
#include&lt;iostream&gt; #include&lt;cstring&gt; using namespace std; const int N = 10,M = 1 &lt;&lt; N, INF = 0x3f3f3f3f; struct Plane { int t,d,l; }p[N]; int n; int f[M]; int main(){ int T; cin &gt;&gt; T; while(T --){ cin &gt;&gt; n; for(int i = 0 ; i &lt; n ; i ++){ int t,d,l; cin &gt;&gt; t &gt;&gt; d &gt;&gt; l; p[i] = {t,d,l}; } memset(f,0x3f,sizeof f); f[0] = 0; for (int i = 1 ; i &lt; 1 &lt;&lt; n; i ++) for (int j = 0 ; j &lt; n; j++) { int t = p[j].t; int d = p[j].d; int l = p[j].l; if(i &gt;&gt; j &amp; 1) { int last = f[i - (1 &lt;&lt; j)]; if (t + d &gt;= last) f[i] = min(f[i],max(last,t) + l); } } if(f[(1 &lt;&lt; n) - 1] &lt; INF) cout &lt;&lt; &#34;YES&#34; &lt;&lt; endl; else cout &lt;&lt; &#34;NO&#34; &lt;&lt;endl; } return 0; } 接龙数列 # 朴素DP # #include&lt;iostream&gt; using namespace std; const int N = 1e5 + 10; int num[N]; int f[N]; int n; int get_high(int x){ while(x/10){ x = x/10; } return x; } int get_low(int x){ return x % 10; } int main(){ scanf(&#34;%d&#34;,&amp;n); for(int i = 0 ; i &lt; n ; i ++){ scanf(&#34;%d&#34;,&amp;num[i]); } for(int i = 0 ; i &lt; n ; i++) { f[i] = 1; for(int j = 0 ; j &lt; i; j ++) { if(get_high(num[i]) == get_low(num[j])) { f[i] = max(f[i],f[j] + 1); } } } int res = 0; for(int i = 0 ; i &lt; n ; i ++){ res = max(res,f[i]); } printf(&#34;%d&#34;,n - res); return 0; } 神奇做法 # 考虑到每个数列只有9种情况，即以1-9结尾。那么可以定义状态数组dp[10] 存储每个以i结尾的数组的长度。考虑到第i个数，是以a开头，b结尾的数。那么dp[b]有两种情况，一种是不加这个数，另外一种是加上这个数 然后就变成了dp[a] + 1，即以a结尾的数加上这个数 然后变成以b结尾的数，所以是dp[a] + 1;然后找到最大的状态就OK
处理数字可以使用string 导入然后首位就是string[0] - &lsquo;0&rsquo;,末尾位就是string.back()- &lsquo;0&rsquo;
#include&lt;iostream&gt; using namespace std; const int N = 10; int dp[N]; int n,ans; int main(){ scanf(&#34;%d&#34;,&amp;n); for(int i = 0 ; i &lt; n ; i ++){ string num; cin &gt;&gt; num; // 这个数以 a 开头 b 结尾 int a = num[0] - &#39;0&#39;; int b = num.back() - &#39;0&#39;; // 以b结尾的可能 只有 // 这个数加上去 然后变成 以a结尾的 数加一， // 或者是 这个不加 dp[b] = max(dp[b],dp[a] + 1); ans = max(ans,dp[b]); } cout &lt;&lt; n - ans ; return 0; }

 题目 # 给你一个整数数组&nbsp;nums ，请计算数组的 中心下标 。
数组 中心下标 是数组的一个下标，其左侧所有元素相加的和等于右侧所有元素相加的和。
如果中心下标位于数组最左端，那么左侧数之和视为 0 ，因为在下标的左侧不存在元素。这一点对于中心下标位于数组最右端同样适用。
如果数组有多个中心下标，应该返回 最靠近左边 的那一个。如果数组不存在中心下标，返回 -1 。
&nbsp;
示例 1：
输入：nums = [1, 7, 3, 6, 5, 6] 输出：3 解释： 中心下标是 3 。 左侧数之和 sum = nums[0] + nums[1] + nums[2] = 1 + 7 + 3 = 11 ， 右侧数之和 sum = nums[4] + nums[5] = 5 + 6 = 11 ，二者相等。 示例 2：
输入：nums = [1, 2, 3] 输出：-1 解释： 数组中不存在满足此条件的中心下标。 示例 3：
输入：nums = [2, 1, -1] 输出：0 解释： 中心下标是 0 。 左侧数之和 sum = 0 ，（下标 0 左侧不存在元素）， 右侧数之和 sum = nums[1] + nums[2] = 1 + -1 = 0 。 &nbsp;
提示：
1 &lt;= nums.length &lt;= 104 -1000 &lt;= nums[i] &lt;= 1000 &nbsp;
分析 # 题解 # class Solution { public: int pivotIndex(vector&lt;int&gt;&amp; nums) { int rsum = 0; int lsum = 0; int len = nums.size(); for(int i = 0; i &lt; len; i++){ rsum += nums[i]; } rsum = rsum - nums[0]; if(rsum == 0) return 0; for(int j = 1; j &lt; len; j++){ rsum = rsum - nums[j]; lsum = lsum + nums[j - 1]; if(rsum == lsum) return j; } return -1; } };

 背包DP # 01背包 # 每件物品最多只用一次。
有 N 件物品和一个容量是 V 的背包。每件物品只能使用一次。 第 i 件物品的体积是 vi，价值是 wi。 求解将哪些物品装入背包，可使这些物品的总体积不超过背包容量，且总价值最大。
输出最大价值。 2. 01背包问题 - AcWing题库
#include&lt;iostream&gt; using namespace std; const int N = 1010; int v[N],w[N]; int m,n; int f[N][N]; int main(){ cin &gt;&gt; m &gt;&gt; n; for(int i = 1; i &lt;= m;i++ ){ cin &gt;&gt; v[i] &gt;&gt; w[i]; } for(int i = 1; i &lt;= m;i++){ for(int j = 0;j&lt;= n;j++) { f[i][j] = f[i - 1][j]; if( j &gt;= v[i]) //当可以装下的空间比第i个大才有可能存在装第i个物品的情况。 f[i][j] = max(f[i][j],f[i - 1][j - v[i]] + w[i]); } } cout &lt;&lt; f[m][n]; return 0; } 优化为二维
#include&lt;iostream&gt; using namespace std; 状态表示 # f(i,j) 表示从前i个背包中选，选出的总权值小于等于j的集合。 f(i,j)的值为总价值。
集合 条件 只从前i中选 选出来的总权值 &lt;j的集合 属性：最大值、最小值、数量。 状态计算 # 表示集合的划分 f(i,j)表示
不包含第i个背包的最优解即f(i-1,j)， 包含第i个背包的最优解即f(i-1,j-w[i])+v[i]。即去掉第i个物品以及总权值减去第i个的权值。 总结： # 第i个背包能不能放，能放就是集合划分第二种，不能放就是第一种。从一步开始走，然后逐渐解决全部问题。
