#include&lt;iostream&gt; using namespace std; const int N = 1010; int n; int a[N],f[N],g[N]; int main(){ scanf(&#34;%d&#34;,&amp;n); for(int i = 1 ; i &lt;= n ; i ++){ scanf(&#34;%d&#34;,&amp;a[i]); } for(int i = 1 ; i &lt;=n ; i ++){ f[i] = 1; for(int j = 1 ; j &lt; i ; j ++){ if(a[i] &gt; a[j]){ if(f[j] + 1 &gt; f[i]){ f[i] = f[j] + 1; g[i] = j; } } } } int k = 0; for(int i = 1 ; i &lt;= n; i++){ // printf(&#34;%d &#34;,f[i]); if(f[i] &gt; f[k]){ k = i; } } printf(&#34;\n%d\n&#34;,f[k]); for(int i = 0 ,len = f[k]; i &lt; len ; i++){ printf(&#34;%d &#34;,a[k]); k = g[k]; } return 0; } 区间DP # 其他 # 3417. 砝码称重 - AcWing题库 砝码称重问题
#include&lt;iostream&gt; using namespace std; const int N = 110; const int MAX = 2e5+10,B = MAX / 2; int w[N]; bool f[N][MAX]; int main(){ int n,m; m = 0; scanf(&#34;%d&#34;,&amp;n); for(int i = 1 ; i &lt;= n ; i++) scanf(&#34;%d&#34;,&amp;w[i]),m += w[i]; f[0][B] = true; for(int i = 1 ; i &lt;= n ; i++){ for(int j = -m ; j &lt;= m ; j ++){ //以下三种情况只要有一种满足 则f[i][j + B] 就满足. //不选 f[i][j + B] = f[i - 1][j + B]; //选,但是放另外一边 if(j + w[i] &lt;= m)f[i][j + B] |= f[i - 1][j + w[i] + B]; //选,但是放一起 if(j - w[i] &gt;= -m)f[i][j + B] |= f[i - 1][j - w[i] + B]; } } int sum = 0; for(int i = 1 ; i &lt;= m ; i++){ if(f[n][i + B]) sum ++; } printf(&#34;%d&#34;,sum); return 0; }

 图论 # Floyd算法 # 主要思想是: 循环邻接矩阵中查找每个点到另外一个点的最短距离，不仅是看直接距离，也还要通过计算中转点。比如计算A到B的距离，要比较A到C的距离与C到B的距离的和、A到B的直接距离的最小值来判断，中转点可以是其他节点，所以代码实现中出现了三重循环。
//n为顶点个数 //第一轮循环为 选取中间点的个数 //第二三轮循环为 void floyd(){ for(int k = 1 ; k &lt;=n ; k++) for(int i = 1 ; i &lt;= n ;i ++) for(int j = 1 ; j &lt;=n ;j ++) dic[i][j] = min(dic[i][j],dic[i][k] + dic[k][j]); } 模板题代码：
#include&lt;iostream&gt; using namespace std; const int N = 210,INF = 1e9; int dic[N][N]; int n,m,Q; void floyd(){ for(int k = 1 ; k &lt;=n ; k++) for(int i = 1 ; i &lt;= n ;i ++) for(int j = 1 ; j &lt;=n ;j ++) dic[i][j] = min(dic[i][j],dic[i][k] + dic[k][j]); } int main(){ scanf(&#34;%d%d%d&#34;,&amp;n,&amp;m,&amp;Q); for(int i = 1 ; i &lt;= n ;i ++) for(int j = 1 ; j&lt;=n;j++) if(i == j) dic[i][j] = 0; else dic[i][j] = INF; while(m--) { int a,b,w; scanf(&#34;%d%d%d&#34;,&amp;a,&amp;b,&amp;w); dic[a][b] = min(dic[a][b],w); } floyd(); while(Q--) { int a,b; scanf(&#34;%d%d&#34;,&amp;a,&amp;b); if(dic[a][b] &lt; INF / 2) printf(&#34;%d&#34;,dic[a][b]); else printf(&#34;impossible&#34;); printf(&#34;\n&#34;); } return 0; }

